#!/bin/bash\n\n# Notification Script for Test Results\n# Usage: ./notify-results.sh [status] [message] [report_url]\n\nSTATUS=${1:-\"unknown\"}\nMESSAGE=${2:-\"Test completed\"}\nREPORT_URL=${3:-\"\"}\nTIMESTAMP=$(date '+%Y-%m-%d %H:%M:%S')\n\n# Load environment variables\nsource .env 2>/dev/null || true\n\n# Slack notification\nsend_slack_notification() {\n    if [ -n \"$SLACK_WEBHOOK\" ]; then\n        local color=\"#36a64f\"  # green\n        if [ \"$STATUS\" = \"FAILURE\" ]; then\n            color=\"#ff0000\"  # red\n        elif [ \"$STATUS\" = \"WARNING\" ]; then\n            color=\"#ffaa00\"  # orange\n        fi\n        \n        local payload=$(cat <<EOF\n{\n    \"attachments\": [\n        {\n            \"color\": \"$color\",\n            \"title\": \"🧪 Playwright Test Results - $STATUS\",\n            \"text\": \"$MESSAGE\",\n            \"fields\": [\n                {\n                    \"title\": \"Timestamp\",\n                    \"value\": \"$TIMESTAMP\",\n                    \"short\": true\n                },\n                {\n                    \"title\": \"Environment\",\n                    \"value\": \"${CI_ENVIRONMENT:-Production}\",\n                    \"short\": true\n                }\n            ],\n            \"actions\": [\n                {\n                    \"type\": \"button\",\n                    \"text\": \"View Report\",\n                    \"url\": \"$REPORT_URL\"\n                }\n            ]\n        }\n    ]\n}\nEOF\n        )\n        \n        curl -X POST \\\n            -H 'Content-type: application/json' \\\n            --data \"$payload\" \\\n            \"$SLACK_WEBHOOK\" || echo \"Failed to send Slack notification\"\n    fi\n}\n\n# Microsoft Teams notification\nsend_teams_notification() {\n    if [ -n \"$TEAMS_WEBHOOK\" ]; then\n        local theme_color=\"00FF00\"  # green\n        if [ \"$STATUS\" = \"FAILURE\" ]; then\n            theme_color=\"FF0000\"  # red\n        elif [ \"$STATUS\" = \"WARNING\" ]; then\n            theme_color=\"FFAA00\"  # orange\n        fi\n        \n        local payload=$(cat <<EOF\n{\n    \"@type\": \"MessageCard\",\n    \"@context\": \"http://schema.org/extensions\",\n    \"themeColor\": \"$theme_color\",\n    \"summary\": \"Playwright Test Results - $STATUS\",\n    \"sections\": [\n        {\n            \"activityTitle\": \"🧪 Playwright Test Results\",\n            \"activitySubtitle\": \"$STATUS\",\n            \"activityImage\": \"https://playwright.dev/img/playwright-logo.svg\",\n            \"facts\": [\n                {\n                    \"name\": \"Status\",\n                    \"value\": \"$STATUS\"\n                },\n                {\n                    \"name\": \"Message\",\n                    \"value\": \"$MESSAGE\"\n                },\n                {\n                    \"name\": \"Timestamp\",\n                    \"value\": \"$TIMESTAMP\"\n                },\n                {\n                    \"name\": \"Environment\",\n                    \"value\": \"${CI_ENVIRONMENT:-Production}\"\n                }\n            ],\n            \"markdown\": true\n        }\n    ],\n    \"potentialAction\": [\n        {\n            \"@type\": \"OpenUri\",\n            \"name\": \"View Report\",\n            \"targets\": [\n                {\n                    \"os\": \"default\",\n                    \"uri\": \"$REPORT_URL\"\n                }\n            ]\n        }\n    ]\n}\nEOF\n        )\n        \n        curl -X POST \\\n            -H 'Content-Type: application/json' \\\n            --data \"$payload\" \\\n            \"$TEAMS_WEBHOOK\" || echo \"Failed to send Teams notification\"\n    fi\n}\n\n# Email notification\nsend_email_notification() {\n    if [ -n \"$EMAIL_RECIPIENTS\" ] && command -v sendmail >/dev/null 2>&1; then\n        local subject=\"Playwright Test Results - $STATUS\"\n        local body=\"Test execution completed at $TIMESTAMP\\n\\nStatus: $STATUS\\nMessage: $MESSAGE\\n\\nReport URL: $REPORT_URL\"\n        \n        echo -e \"Subject: $subject\\n\\n$body\" | sendmail \"$EMAIL_RECIPIENTS\" || echo \"Failed to send email notification\"\n    fi\n}\n\n# Discord notification\nsend_discord_notification() {\n    if [ -n \"$DISCORD_WEBHOOK\" ]; then\n        local color=65280  # green\n        if [ \"$STATUS\" = \"FAILURE\" ]; then\n            color=16711680  # red\n        elif [ \"$STATUS\" = \"WARNING\" ]; then\n            color=16753920  # orange\n        fi\n        \n        local payload=$(cat <<EOF\n{\n    \"embeds\": [\n        {\n            \"title\": \"🧪 Playwright Test Results\",\n            \"description\": \"$MESSAGE\",\n            \"color\": $color,\n            \"fields\": [\n                {\n                    \"name\": \"Status\",\n                    \"value\": \"$STATUS\",\n                    \"inline\": true\n                },\n                {\n                    \"name\": \"Timestamp\",\n                    \"value\": \"$TIMESTAMP\",\n                    \"inline\": true\n                },\n                {\n                    \"name\": \"Environment\",\n                    \"value\": \"${CI_ENVIRONMENT:-Production}\",\n                    \"inline\": true\n                }\n            ],\n            \"url\": \"$REPORT_URL\"\n        }\n    ]\n}\nEOF\n        )\n        \n        curl -X POST \\\n            -H 'Content-Type: application/json' \\\n            --data \"$payload\" \\\n            \"$DISCORD_WEBHOOK\" || echo \"Failed to send Discord notification\"\n    fi\n}\n\n# Send all configured notifications\necho \"Sending notifications for status: $STATUS\"\nsend_slack_notification\nsend_teams_notification\nsend_email_notification\nsend_discord_notification\necho \"Notification dispatch completed\"